import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import NotificationBell from '../components/NotificationBell';
import {
  getAdminStatistics, getAdminDoctors, getAdminReceptionists,
  getUnavailableDoctors, createDoctor, createReceptionist, createClinic,
  getClinics, getAdminCities, getSpecializations, postBulletin,
  getBulletinsByAdmin, deleteBulletin, getUnavailabilityRequests,
  approveUnavailability, rejectUnavailability, monitorDoctors,
  requestPasswordChange, requestContactChange, requestGeneralQuery,
} from '../api';

const TABS = ['Dashboard', 'Staff', 'Clinics', 'Monitoring', 'Bulletins', 'Requests'];
const PRIMARY = '#1565c0';

export default function Admin() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [tab, setTab]               = useState(0);
  const [stats, setStats]           = useState({});
  const [doctors, setDoctors]       = useState([]);
  const [receptionists, setReceps]  = useState([]);
  const [unavailDoctors, setUnavail] = useState([]);
  const [clinics, setClinics]       = useState([]);
  const [cities, setCities]         = useState([]);
  const [specs, setSpecs]           = useState([]);
  const [bulletins, setBulletins]   = useState([]);
  const [unavailReqs, setUnavailReqs] = useState([]);
  const [queueData, setQueueData]   = useState([]);
  const [msg, setMsg]               = useState({ text:'', ok:true });

  const [docForm,     setDocForm]     = useState({ username:'',email:'',password:'',name:'',contact:'',clinic_id:'',license_number:'',specialization_id:'' });
  const [recepForm,   setRecepForm]   = useState({ username:'',email:'',password:'',name:'',contact:'',clinic_id:'' });
  const [clinicForm,  setClinicForm]  = useState({ name:'',location:'',city_id:'' });
  const [bulletinForm,setBulletinForm]= useState({ title:'',message:'' });
  const [pwForm,      setPwForm]      = useState({ new_password:'' });
  const [ctForm,      setCtForm]      = useState({ new_contact:'' });
  const [queryForm,   setQueryForm]   = useState({ query:'',reason:'' });

  const { admin_id, company_id } = user;

  useEffect(() => { loadBase(); }, []);

  const loadBase = async () => {
    const [st, docs, receps, unavail, cl, ct, sp] = await Promise.all([
      getAdminStatistics({ company_id, admin_id }),
      getAdminDoctors({ company_id, admin_id }),
      getAdminReceptionists({ company_id, admin_id }),
      getUnavailableDoctors(admin_id),
      getClinics({ company_id, admin_id }),
      getAdminCities(admin_id),
      getSpecializations(),
    ]);
    setStats(st);
    setDoctors(docs.doctors || []);
    setReceps(receps.receptionists || []);
    setUnavail(unavail.doctors || []);
    setClinics(cl.clinics || []);
    setCities(ct.cities || []);
    setSpecs(sp.specializations || []);
  };

  const handleTab = async (i) => {
    setTab(i);
    if (i === 3) { const d = await monitorDoctors(); setQueueData(d.doctors || []); }
    if (i === 4) { const b = await getBulletinsByAdmin(admin_id); setBulletins(b.bulletins || []); }
    if (i === 5) { const r = await getUnavailabilityRequests(admin_id); setUnavailReqs(r.requests || []); }
  };

  const flash = (text, ok = true) => { setMsg({ text, ok }); setTimeout(() => setMsg({ text:'', ok:true }), 4000); };

  const submit = (fn, successMsg, reset) => async (e) => {
    e.preventDefault();
    try { await fn(); flash(successMsg); if (reset) reset(); loadBase(); }
    catch (err) { flash(err.response?.data?.detail || 'Error', false); }
  };

  return (
    <div style={s.page}>
      <header style={s.header}>
        <div style={s.hl}><span style={s.logo}>💊 CareLine</span><span style={s.roleTag}>Admin</span></div>
        <div style={s.hr}>
          <span style={s.welcome}>{user.name} — {user.company_name}</span>
          <NotificationBell role="admin" userId={admin_id} />
          <button style={s.logoutBtn} onClick={() => { logout(); navigate('/login'); }}>Logout</button>
        </div>
      </header>

      {msg.text && <div style={{ ...s.flash, background: msg.ok ? '#2e7d32' : '#c62828' }}>{msg.text}</div>}

      <nav style={s.tabs}>
        {TABS.map((t, i) => <button key={t} style={tab===i ? s.tabOn : s.tabOff} onClick={() => handleTab(i)}>{t}</button>)}
      </nav>

      <main style={s.main}>

        {/* ── DASHBOARD ── */}
        {tab === 0 && <>
          <div style={s.statGrid}>
            {[['🏥 Clinics', stats.total_clinics],['👨‍⚕️ Doctors', stats.total_doctors],['🧑‍💼 Receptionists', stats.total_receptionists],['📋 Appointments', stats.total_appointments]].map(([l,v]) => (
              <div key={l} style={s.statCard}><div style={s.statVal}>{v ?? '…'}</div><div style={s.statLbl}>{l}</div></div>
            ))}
          </div>
          {unavailDoctors.length > 0 && (
            <div style={s.alert}>
              <strong>⚠️ Unavailable Doctors ({unavailDoctors.length})</strong>
              {unavailDoctors.map(d => <div key={d.id} style={s.alertRow}>{d.name} — {d.clinic_name}</div>)}
            </div>
          )}
          <h3>Doctors</h3>
          <DataTable cols={['Name','Clinic','Specialization','License','Status']}
            rows={doctors.map(d => [d.name, d.clinic_name, d.specialization||'—', d.license_number, <Chip status={d.status}/>])} />
          <h3 style={{ marginTop:20 }}>Receptionists</h3>
          <DataTable cols={['Name','Clinic','City','Contact']}
            rows={receptionists.map(r => [r.name, r.clinic_name, r.city_name, r.contact])} />
        </>}

        {/* ── STAFF ── */}
        {tab === 1 && <div style={s.twoCol}>
          <Card title="Create Doctor">
            <form onSubmit={submit(() => createDoctor({...docForm,clinic_id:+docForm.clinic_id,specialization_id:+docForm.specialization_id}), 'Doctor created!', () => setDocForm({ username:'',email:'',password:'',name:'',contact:'',clinic_id:'',license_number:'',specialization_id:'' }))} style={s.col}>
              {['username','email','password','name','contact','license_number'].map(k => <F key={k} label={k} type={k==='password'?'password':'text'} val={docForm[k]} set={v => setDocForm(f=>({...f,[k]:v}))} />)}
              <Sel label="Clinic" val={docForm.clinic_id} set={v => setDocForm(f=>({...f,clinic_id:v}))} opts={clinics.map(c=>({id:c.id,label:c.name}))} />
              <Sel label="Specialization" val={docForm.specialization_id} set={v => setDocForm(f=>({...f,specialization_id:v}))} opts={specs.map(sp=>({id:sp.id,label:sp.name}))} />
              <button style={s.btn} type="submit">Create Doctor</button>
            </form>
          </Card>
          <Card title="Create Receptionist">
            <form onSubmit={submit(() => createReceptionist({...recepForm,clinic_id:+recepForm.clinic_id}), 'Receptionist created!', () => setRecepForm({ username:'',email:'',password:'',name:'',contact:'',clinic_id:'' }))} style={s.col}>
              {['username','email','password','name','contact'].map(k => <F key={k} label={k} type={k==='password'?'password':'text'} val={recepForm[k]} set={v => setRecepForm(f=>({...f,[k]:v}))} />)}
              <Sel label="Clinic" val={recepForm.clinic_id} set={v => setRecepForm(f=>({...f,clinic_id:v}))} opts={clinics.map(c=>({id:c.id,label:c.name}))} />
              <button style={s.btn} type="submit">Create Receptionist</button>
            </form>
          </Card>
        </div>}

        {/* ── CLINICS ── */}
        {tab === 2 && <div style={s.twoCol}>
          <Card title="Create Clinic">
            <form onSubmit={submit(() => createClinic({...clinicForm,company_id,city_id:+clinicForm.city_id}), 'Clinic created!', () => setClinicForm({ name:'',location:'',city_id:'' }))} style={s.col}>
              <F label="Name" val={clinicForm.name} set={v => setClinicForm(f=>({...f,name:v}))} />
              <F label="Location" val={clinicForm.location} set={v => setClinicForm(f=>({...f,location:v}))} />
              <Sel label="City" val={clinicForm.city_id} set={v => setClinicForm(f=>({...f,city_id:v}))} opts={cities.map(c=>({id:c.id,label:`${c.name} — ${c.sub_region}, ${c.province}`}))} />
              <button style={s.btn} type="submit">Create Clinic</button>
            </form>
          </Card>
          <Card title="My Clinics">
            {clinics.map(c => <div key={c.id} style={s.listItem}><strong>{c.name}</strong><div style={s.sub}>{c.location} — {c.city_name}</div><Chip status={c.status}/></div>)}
          </Card>
        </div>}

        {/* ── MONITORING ── */}
        {tab === 3 && <>
          <h3>Doctor Queue</h3>
          <DataTable cols={['Doctor','Clinic','Status','Queue']}
            rows={queueData.map(d=>[d.name,d.clinic_name,<Chip status={d.status}/>,d.queue_length])} />
          <h3 style={{ marginTop:20 }}>Pending Unavailability Requests</h3>
          {unavailReqs.length === 0 ? <p style={s.empty}>None pending.</p> : unavailReqs.map(r => (
            <div key={r.id} style={s.listItem}>
              <strong>{r.doctor_name}</strong> — {r.clinic_name}
              <div style={s.sub}>{new Date(r.start_datetime).toLocaleDateString()} → {new Date(r.end_datetime).toLocaleDateString()}</div>
              <div style={s.sub}>{r.reason}</div>
              <div style={{ display:'flex', gap:8, marginTop:8 }}>
                <button style={s.okBtn} onClick={async () => { await approveUnavailability(r.id, admin_id); flash('Approved.'); const res = await getUnavailabilityRequests(admin_id); setUnavailReqs(res.requests||[]); }}>✓ Approve</button>
                <button style={s.noBtn} onClick={async () => { const reason = prompt('Rejection reason:'); if (!reason) return; await rejectUnavailability(r.id, admin_id, reason); flash('Rejected.'); const res = await getUnavailabilityRequests(admin_id); setUnavailReqs(res.requests||[]); }}>✗ Reject</button>
              </div>
            </div>
          ))}
        </>}

        {/* ── BULLETINS ── */}
        {tab === 4 && <div style={s.twoCol}>
          <Card title="Post Bulletin">
            <form onSubmit={submit(() => postBulletin({...bulletinForm,company_id}), 'Bulletin posted!', async () => { setBulletinForm({ title:'',message:'' }); const b = await getBulletinsByAdmin(admin_id); setBulletins(b.bulletins||[]); })} style={s.col}>
              <F label="Title" val={bulletinForm.title} set={v => setBulletinForm(f=>({...f,title:v}))} />
              <label style={s.lbl}>Message<textarea style={{...s.inp,resize:'vertical'}} rows={4} value={bulletinForm.message} onChange={e=>setBulletinForm(f=>({...f,message:e.target.value}))} required /></label>
              <button style={s.btn} type="submit">Post</button>
            </form>
          </Card>
          <div>
            <h3>Active Bulletins</h3>
            {bulletins.length===0 && <p style={s.empty}>None yet.</p>}
            {bulletins.map(b => (
              <div key={b.id} style={s.listItem}>
                <strong>{b.title}</strong>
                <p style={{ margin:'6px 0', fontSize:'.88rem' }}>{b.message}</p>
                <div style={{ display:'flex', justifyContent:'space-between' }}>
                  <span style={s.sub}>{new Date(b.created_at).toLocaleDateString()}</span>
                  <button style={s.noBtn} onClick={async () => { await deleteBulletin(b.id, admin_id); flash('Deleted.'); const res = await getBulletinsByAdmin(admin_id); setBulletins(res.bulletins||[]); }}>Delete</button>
                </div>
              </div>
            ))}
          </div>
        </div>}

        {/* ── REQUESTS ── */}
        {tab === 5 && <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:20 }}>
          <Card title="Change Password">
            <form onSubmit={submit(() => requestPasswordChange({ admin_id, new_password: pwForm.new_password }), 'Request submitted.', () => setPwForm({ new_password:'' }))} style={s.col}>
              <F label="New Password" type="password" val={pwForm.new_password} set={v => setPwForm({ new_password:v })} />
              <button style={s.btn} type="submit">Submit</button>
            </form>
          </Card>
          <Card title="Change Contact">
            <form onSubmit={submit(() => requestContactChange({ admin_id, new_contact: ctForm.new_contact }), 'Request submitted.', () => setCtForm({ new_contact:'' }))} style={s.col}>
              <F label="New Contact" val={ctForm.new_contact} set={v => setCtForm({ new_contact:v })} />
              <button style={s.btn} type="submit">Submit</button>
            </form>
          </Card>
          <Card title="General Query">
            <form onSubmit={submit(() => requestGeneralQuery({ admin_id, ...queryForm }), 'Query submitted.', () => setQueryForm({ query:'',reason:'' }))} style={s.col}>
              <F label="Query" val={queryForm.query} set={v => setQueryForm(f=>({...f,query:v}))} />
              <label style={s.lbl}>Reason<textarea style={s.inp} rows={3} value={queryForm.reason} onChange={e=>setQueryForm(f=>({...f,reason:e.target.value}))} /></label>
              <button style={s.btn} type="submit">Submit</button>
            </form>
          </Card>
        </div>}

      </main>
    </div>
  );
}

// ── Small reusable helpers ──
function Card({ title, children }) {
  return <div style={s.card}><h3 style={{ marginTop:0 }}>{title}</h3>{children}</div>;
}
function F({ label, type='text', val, set, placeholder }) {
  return <label style={s.lbl}>{label.charAt(0).toUpperCase()+label.slice(1).replace('_',' ')}<input style={s.inp} type={type} value={val} onChange={e=>set(e.target.value)} placeholder={placeholder} required /></label>;
}
function Sel({ label, val, set, opts }) {
  return <label style={s.lbl}>{label}<select style={s.inp} value={val} onChange={e=>set(e.target.value)} required><option value="">Select…</option>{opts.map(o=><option key={o.id} value={o.id}>{o.label}</option>)}</select></label>;
}
function Chip({ status }) {
  return <span style={{ background: status==='active'?'#4caf50':'#f44336', color:'white', borderRadius:12, padding:'2px 9px', fontSize:'.72rem', fontWeight:700 }}>{status}</span>;
}
function DataTable({ cols, rows }) {
  return <div style={{ overflowX:'auto' }}><table style={s.table}><thead><tr>{cols.map(c=><th key={c} style={s.th}>{c}</th>)}</tr></thead><tbody>{rows.map((r,i)=><tr key={i}>{r.map((c,j)=><td key={j} style={s.td}>{c}</td>)}</tr>)}</tbody></table></div>;
}

